mapper.select:
SELECT o.price FROM transactions t
JOIN orders o ON t.buy_order_id = o.order_id WHERE o.stock_id = #{stockId}
ORDER BY t.created_date DESC LIMIT 1

SELECT order_id FROM orders
WHERE content = #{content} AND student_id = (SELECT id FROM students WHERE student_id = #{studentId}) AND stock_id = #{stockId}
AND state = #{state} AND amount = #{amount} AND price = #{price} ORDER BY created_date DESC LIMIT 1
